// Extract parameters from clause source string
// For "num_threads(4)", returns "4"
// For "private(a, b, c)", returns "a, b, c"
// For "nowait", returns ""
static std::string extractClauseParameters(const char* clause_source) {
    if (!clause_source) return "";

    std::string source(clause_source);
    size_t open_paren = source.find('(');

    if (open_paren == std::string::npos) {
        // No parameters (e.g., "nowait")
        return "";
    }

    size_t close_paren = source.rfind(')');
    if (close_paren == std::string::npos || close_paren <= open_paren) {
        return "";
    }

    // Extract content between parentheses
    return source.substr(open_paren + 1, close_paren - open_paren - 1);
}

// Parse comma-separated list into vector of strings
static std::vector<std::string> parseCommaSeparatedList(const std::string& input) {
    std::vector<std::string> result;
    if (input.empty()) return result;

    std::string current;
    int paren_depth = 0;
    int bracket_depth = 0;

    for (char c : input) {
        if (c == '(') {
            paren_depth++;
            current += c;
        } else if (c == ')') {
            paren_depth--;
            current += c;
        } else if (c == '[') {
            bracket_depth++;
            current += c;
        } else if (c == ']') {
            bracket_depth--;
            current += c;
        } else if (c == ',' && paren_depth == 0 && bracket_depth == 0) {
            // Top-level comma - split here
            // Trim whitespace
            size_t start = current.find_first_not_of(" \t");
            size_t end = current.find_last_not_of(" \t");
            if (start != std::string::npos) {
                result.push_back(current.substr(start, end - start + 1));
            }
            current.clear();
        } else {
            current += c;
        }
    }

    // Add last item
    size_t start = current.find_first_not_of(" \t");
    size_t end = current.find_last_not_of(" \t");
    if (start != std::string::npos) {
        result.push_back(current.substr(start, end - start + 1));
    }

    return result;
}

// Helper to map reduction operator string to enum
static OpenMPReductionClauseIdentifier mapReductionOperator(const std::string& op) {
    if (op == "+" || op == "plus") return OMPC_REDUCTION_IDENTIFIER_plus;
    if (op == "-" || op == "minus") return OMPC_REDUCTION_IDENTIFIER_minus;
    if (op == "*" || op == "mul") return OMPC_REDUCTION_IDENTIFIER_mul;
    if (op == "&" || op == "bitand") return OMPC_REDUCTION_IDENTIFIER_bitand;
    if (op == "|" || op == "bitor") return OMPC_REDUCTION_IDENTIFIER_bitor;
    if (op == "^" || op == "bitxor") return OMPC_REDUCTION_IDENTIFIER_bitxor;
    if (op == "&&" || op == "logand") return OMPC_REDUCTION_IDENTIFIER_logand;
    if (op == "||" || op == "logor") return OMPC_REDUCTION_IDENTIFIER_logor;
    if (op == "max") return OMPC_REDUCTION_IDENTIFIER_max;
    if (op == "min") return OMPC_REDUCTION_IDENTIFIER_min;
    if (op == ".eqv." || op == "eqv") return OMPC_REDUCTION_IDENTIFIER_eqv;
    if (op == ".neqv." || op == "neqv") return OMPC_REDUCTION_IDENTIFIER_neqv;
    return OMPC_REDUCTION_IDENTIFIER_user;
}

